define("local_edukav/partners",["core/ajax"],(function(Ajax){var started=!1,observer=null;function escapeAttribute(value){return String(value||"").replace(/&/g,"&amp;").replace(/"/g,"&quot;").replace(/'/g,"&#39;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}function renderLogo(target,data){target.innerHTML="",target.insertAdjacentHTML("beforeend",'<img src="'.concat(escapeAttribute(data.logo),'" class="rbt-partner-logo" title="').concat(escapeAttribute(data.name),'" alt="').concat(escapeAttribute(data.name),'">'))}function renderPartner(card,data){if(data&&data.found&&data.logo){var target=card.querySelector(".partner-card, .partner-list, .partner-summary");target&&renderLogo(target,data)}}function scanCards(){var cards=[];document.querySelectorAll(".partner-card, .partner-list, .partner-summary").forEach((function(target){var card=target.closest("[data-course-id]");card&&-1===cards.indexOf(card)&&cards.push(card)})),cards.forEach((function(card){if("1"!==card.dataset.loaded){var courseid=parseInt(card.dataset.courseId,10);courseid&&(card.dataset.loaded="1",Ajax.call([{methodname:"local_edukav_get_course_partner",args:{courseid:courseid}}])[0].done((function(response){renderPartner(card,response)})))}}))}return{init:function(){started?scanCards():(started=!0,scanCards(),window.MutationObserver&&(observer=new MutationObserver((function(){scanCards()})),observer.observe(document.body,{childList:!0,subtree:!0})))}}}));
